import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"ADR-0002: 时间检索 — time_range 门控 + 正则快通道，不做第三路融合","description":"","frontmatter":{},"headers":[],"relativePath":"adr/0002-time-range-retrieval.md","filePath":"adr/0002-time-range-retrieval.md","lastUpdated":1784633569000}'),o={name:"adr/0002-time-range-retrieval.md"};function l(n,a,s,h,d,u){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="adr-0002-时间检索-—-time-range-门控-正则快通道-不做第三路融合" tabindex="-1">ADR-0002: 时间检索 — time_range 门控 + 正则快通道，不做第三路融合 <a class="header-anchor" href="#adr-0002-时间检索-—-time-range-门控-正则快通道-不做第三路融合" aria-label="Permalink to &quot;ADR-0002: 时间检索 — time_range 门控 + 正则快通道，不做第三路融合&quot;">​</a></h1><ul><li><strong>状态</strong>：Proposed（2026-07-21，随 PR 评审定稿）</li><li><strong>日期</strong>：2026-07-21</li><li><strong>关联</strong>：<a href="./0001-diary-store.html">ADR-0001</a>（日记原语，本决策的检索对象）、<a href="https://github.com/NevaMind-AI/MemU/blob/main/docs/adr/0007-agentic-file-memory-v3.md" target="_blank" rel="noreferrer">memU ADR-0007</a>（min-max 融合公式来源）、XnneHangLab ADR-0004（宿主侧时间意图识别 tool call）</li></ul><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>需求：回答&quot;前天晚上我吃了什么&quot;类查询。时间没有相关性分数，无法进现有的 min-max 加权融合；直觉备选是把三路（BM25 / 向量 / 时间）全改 RRF 排名融合。</p><p>设计讨论（博客《RRF vs Hybrid Search》）得出的关键分析：</p><ol><li><strong>时间和另外两路不是同类信号</strong>。语义分和关键词分回答&quot;这条记忆是不是在说这件事&quot;——相关性，适合投票；时间回答&quot;这条记忆在不在所问的范围里&quot;——约束。窗口外的记忆不是&quot;不太相关&quot;，是<strong>错的</strong>。约束不该投票，该过滤。</li><li><strong>无条件投票者 = 系统性偏置</strong>。BM25/向量的候选列表是查询条件化的——不匹配就缺席；时间对任何 query 都能排出完整榜单。让它永远参与 RRF 投票，等于给所有查询注入 recency 噪声。</li><li><strong>三路 RRF 也省不掉时间解析器</strong>。时间路要有意义，得先把&quot;前天晚上&quot;解析成区间才能按距离排序——解析器横竖要写；而解析完手里已有区间，投票反而是绕路：投票保证不了赢家落在区间内（一条三周前印象深刻的晚餐可能在语义上碾压前天那顿平平无奇的）。</li><li>&quot;双融合 + 分歧触发&quot;的触发器测错了对象：时间榜与语义榜分歧是<strong>常态</strong>不是信号，&quot;该不该用时间&quot;的证据在 query 里。</li></ol><p>结论：<strong>时间做门控（pre-filter），不做检索路。</strong></p><h2 id="决策" tabindex="-1">决策 <a class="header-anchor" href="#决策" aria-label="Permalink to &quot;决策&quot;">​</a></h2><h3 id="_1-api-一个参数-两条来路" tabindex="-1">1. API：一个参数，两条来路 <a class="header-anchor" href="#_1-api-一个参数-两条来路" aria-label="Permalink to &quot;1. API：一个参数，两条来路&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index.retrieve(query, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">time_range</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">None</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><ul><li><strong>time_range 显式传入</strong>（宿主意图识别 / tool call 的出口）→ 直接使用，跳过内部解析。</li><li><strong>未传入</strong> → <strong>正则快通道</strong>：纯 stdlib（<code>re</code> + <code>datetime</code>）解析可枚举的时间表达（昨天 / 前天 / 上周X / X天前 / X月X号 / ISO 日期等，清单实现期定，<strong>宁窄勿误</strong>——解析不出就当无时间意图，不猜）。命中即开窗。</li><li>不引入 dateparser / arrow / TimeNLP——零依赖硬约束优先，<code>timedelta</code> 能算的事不加库。</li><li><strong>正则是框架的地板，LLM 是宿主的天花板，中间不存在第三个解析器。</strong></li></ul><h3 id="_2-门控语义" tabindex="-1">2. 门控语义 <a class="header-anchor" href="#_2-门控语义" aria-label="Permalink to &quot;2. 门控语义&quot;">​</a></h3><p>窗口 → 日记文件集（文件名即时间索引，<a href="./0001-diary-store.html">ADR-0001</a>）→ 在窗口内候选集上执行<strong>现有检索原样不动</strong>（BM25 即时构建；向量走既有 content-hash 缓存按窗口子集过滤）。<strong>min-max 融合公式零改动。</strong></p><h3 id="_3-退化情形-时间独立工作" tabindex="-1">3. 退化情形：时间独立工作 <a class="header-anchor" href="#_3-退化情形-时间独立工作" aria-label="Permalink to &quot;3. 退化情形：时间独立工作&quot;">​</a></h3><p>query 为空或无实义、但有窗口 → 按时间倒序取 top-N。这就是 MoeChat&quot;整段召回日记&quot;行为的受控版——时间检索无需第三路投票也能独立工作。</p><h3 id="_4-兜底-放宽而非空手" tabindex="-1">4. 兜底：放宽而非空手 <a class="header-anchor" href="#_4-兜底-放宽而非空手" aria-label="Permalink to &quot;4. 兜底：放宽而非空手&quot;">​</a></h3><p>窗口内零命中 → 自动放宽（如 ±1 天；&quot;上周中午&quot;这类模糊边界直接取宽区间），<code>explain=True</code> 中标注放宽动作。仍零命中才返回空（fail-open 由宿主处理）。别让一次误解析变成&quot;我不记得了&quot;。</p><h3 id="_5-时区" tabindex="-1">5. 时区 <a class="header-anchor" href="#_5-时区" aria-label="Permalink to &quot;5. 时区&quot;">​</a></h3><p>存储 <code>ts</code> 保持 UTC ISO-8601 不变；正则快通道解析&quot;昨天&quot;这类相对表达时使用<strong>传入的 tz 参数</strong>（缺省取系统本地时区），窗口比较统一换算到 UTC。</p><h3 id="_6-可选-recency-衰减项-隐式新鲜度" tabindex="-1">6. 可选 recency 衰减项（隐式新鲜度） <a class="header-anchor" href="#_6-可选-recency-衰减项-隐式新鲜度" aria-label="Permalink to &quot;6. 可选 recency 衰减项（隐式新鲜度）&quot;">​</a></h3><p>用户没提时间、但新近记忆应更易浮现的需求，<strong>不做第三路</strong>：作为小权重衰减项（形如 <code>exp(-Δt/τ)</code>）参与现有 min-max 分数融合。默认关闭，是否默认开启由 bench 数据决定。</p><h3 id="_7-永不" tabindex="-1">7. 永不 <a class="header-anchor" href="#_7-永不" aria-label="Permalink to &quot;7. 永不&quot;">​</a></h3><ul><li>时间永不作为 RRF / 融合的投票路。</li><li>wiki 状态层默认不受 time_range 影响——时间轴只属于日记（&quot;上周新增的偏好&quot;这类过滤需求出现了再议）。</li></ul><h2 id="理由" tabindex="-1">理由 <a class="header-anchor" href="#理由" aria-label="Permalink to &quot;理由&quot;">​</a></h2><ul><li>门控在工程上就是向量检索里标准的 metadata pre-filter，成熟、可解释、零公式改动。</li><li>显式时间指称是硬约束（过滤），隐式新鲜度是软偏好（衰减项）——时间的两个角色各得其所，&quot;第三路&quot;这个概念整体消失。</li><li>事件锚定的两跳查询（&quot;上次我们吵架那天&quot;→ 先检索事件拿日期，再开窗）天然由门控支持，由宿主 tool call 编排；投票路线根本无法表达。</li></ul><h2 id="后果" tabindex="-1">后果 <a class="header-anchor" href="#后果" aria-label="Permalink to &quot;后果&quot;">​</a></h2><p><strong>正面</strong></p><ul><li>时间检索可独立工作（退化情形），也可与语义检索组合（窗口内 hybrid）。</li><li>融合公式、explain、token 预算裁剪全部复用，改动面收敛在&quot;候选集从哪来&quot;。</li></ul><p><strong>负面 / 代价</strong></p><ul><li>正则清单是一个持续维护面（中文时间表达是开放集）。缓解：宁窄勿误 + 解析不出交给宿主 LLM。</li><li>窗口内 BM25 即时构建有小成本（天级文件量可忽略；全库 BM25 索引现状不变）。</li><li><code>time_range</code> 的边界语义（闭开区间、跨时区日界）需在 API 文档一次性钉死。</li></ul><p><strong>实施</strong></p><p>依赖 <a href="./0001-diary-store.html">ADR-0001</a> 落地；建议同一里程碑（M5）内实现：快通道解析器（含测试表）→ 窗口检索 → explain 扩展。</p>',32)])])}const g=e(o,[["render",l]]);export{p as __pageData,g as default};
